patch:
--- a/datapath.sv
+++ b/datapath.sv
@@ -1,17 +1,17 @@
 module alu(
   input [15:0] operand_a,
   input [15:0] operand_b,
   input [3:0] operation,
   output [15:0] result,
-  output [3:0] flags
+  output [2:0] flags
 );
   always @(*) begin
     case (operation)
       4'b0000: result = operand_a + operand_b;
       4'b0001: result = operand_a - operand_b;
       4'b0010: result = operand_a & operand_b;
       4'b0011: result = operand_a | operand_b;
       default: result = 16'b0;
     endcase
-    flags = {result[15], (result == 0), 2'b0};
+    flags = {result[15], (result == 0), 1'b0};
   end
 endmodule

@@ -10,9 +10,9 @@
   input [15:0] b,
   input [3:0] op,
   output [15:0] res,
-  output [3:0] stat
+  output [2:0] stat
 );
-  alu alu_inst(.operand_a(a), .operand_b(b), .operation(op), .result(res), .flags(stat[3:0]));
+  alu alu_inst(.operand_a(a), .operand_b(b), .operation(op), .result(res), .flags(stat));
 endmodule

before_code:
module alu(
  input [15:0] operand_a,
  input [15:0] operand_b,
  input [3:0] operation,
  output [15:0] result,
  output [3:0] flags
);
  always @(*) begin
    case (operation)
      4'b0000: result = operand_a + operand_b;
      4'b0001: result = operand_a - operand_b;
      4'b0010: result = operand_a & operand_b;
      4'b0011: result = operand_a | operand_b;
      default: result = 16'b0;
    endcase
    flags = {result[15], (result == 0), 2'b0};
  end
endmodule

module processor(
  input [15:0] a, b,
  input [3:0] op,
  output [15:0] res,
  output [3:0] stat
);
  alu alu_inst(.operand_a(a), .operand_b(b), .operation(op), .result(res), .flags(stat[3:0]));
endmodule

after_code:
module alu(
  input [15:0] operand_a,
  input [15:0] operand_b,
  input [3:0] operation,
  output [15:0] result,
  output [2:0] flags
);
  always @(*) begin
    case (operation)
      4'b0000: result = operand_a + operand_b;
      4'b0001: result = operand_a - operand_b;
      4'b0010: result = operand_a & operand_b;
      4'b0011: result = operand_a | operand_b;
      default: result = 16'b0;
    endcase
    flags = {result[15], (result == 0), 1'b0};
  end
endmodule

module processor(
  input [15:0] a, b,
  input [3:0] op,
  output [15:0] res,
  output [2:0] stat
);
  alu alu_inst(.operand_a(a), .operand_b(b), .operation(op), .result(res), .flags(stat));
endmodule
